import React from "react";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import "swiper/css/navigation";
import { Autoplay, Navigation } from "swiper/modules";
import HeaderBanner1 from "../../assets/images/header_banner_1.png";
import HeaderBanner2 from "../../assets/images/header_banner_2.png";
import HeaderBanner3 from "../../assets/images/header_banner_3.png";
import HeaderBanner4 from "../../assets/images/header_banner_3.png";

const HomeBanner = () => {
  return (
    <div className="container mt-3">
      <div className="homeBannerSection">
        <Swiper
          slidesPerView={1}
          spaceBetween={15}
          navigation={true}
          loop={false}
          autoplay={{
            delay: 2500,
            disableOnInteraction: false,
          }}
          modules={[Navigation, Autoplay]} // Sử dụng dấu ngoặc vuông thay vì dấu ngoặc nhọn
          className="mySwiper"
        >
          <SwiperSlide>
            <div className="item">
              <img src={HeaderBanner1} className="w-100" alt="Banner 1" />
            </div>
          </SwiperSlide>
          <SwiperSlide>
            <div className="item">
              <img src={HeaderBanner2} className="w-100" alt="Banner 2" />
            </div>
          </SwiperSlide>
          <SwiperSlide>
            <div className="item">
              <img src={HeaderBanner3} className="w-100" alt="Banner 3" />
            </div>
          </SwiperSlide>
          <SwiperSlide>
            <div className="item">
              <img src={HeaderBanner4} className="w-100" alt="Banner 4" />
            </div>
          </SwiperSlide>
        </Swiper>
      </div>
    </div>
  );
};

export default HomeBanner;
